#!/usr/bin/env python3
"""TASK-1: Add CollectFailurePolicy enum, field on Task/InFlightTask, and re-exports"""
import base64, json, subprocess, sys
from pathlib import Path

TASK_ID = "TASK-1"
STEPS = json.loads('[{"before_b64": "", "after_b64": "", "target": "/Users/tony/programming/castep_workflow_framework/workflow_core/src/task.rs", "index": 0, "is_create": false}, {"before_b64": "cHViIHVzZSB0YXNrOjp7RXhlY3V0aW9uTW9kZSwgVGFzaywgVGFza0Nsb3N1cmV9Ow==", "after_b64": "cHViIHVzZSB0YXNrOjp7Q29sbGVjdEZhaWx1cmVQb2xpY3ksIEV4ZWN1dGlvbk1vZGUsIFRhc2ssIFRhc2tDbG9zdXJlfTs=", "target": "/Users/tony/programming/castep_workflow_framework/workflow_core/src/lib.rs", "index": 1, "is_create": false}, {"before_b64": "cHViIHVzZSBjcmF0ZTo6dGFzazo6e0V4ZWN1dGlvbk1vZGUsIFRhc2t9Ow==", "after_b64": "cHViIHVzZSBjcmF0ZTo6dGFzazo6e0NvbGxlY3RGYWlsdXJlUG9saWN5LCBFeGVjdXRpb25Nb2RlLCBUYXNrfTs=", "target": "/Users/tony/programming/castep_workflow_framework/workflow_core/src/prelude.rs", "index": 2, "is_create": false}, {"before_b64": "", "after_b64": "", "target": "/Users/tony/programming/castep_workflow_framework/workflow_core/src/workflow.rs", "index": 3, "is_create": false}, {"before_b64": "", "after_b64": "", "target": "/Users/tony/programming/castep_workflow_framework/workflow_core/src/workflow.rs", "index": 4, "is_create": false}]')

for step in STEPS:
    before = base64.b64decode(step["before_b64"]).decode()
    after = base64.b64decode(step["after_b64"]).decode()
    target = step["target"]
    idx = step["index"]
    is_create = step["is_create"]

    if is_create:
        target_path = Path(target)
        target_path.parent.mkdir(parents=True, exist_ok=True)
        target_path.write_text(after)
        print(f"OK {TASK_ID} change {idx}: created {target}")
    else:
        target_path = Path(target)
        content = target_path.read_text()
        if before not in content:
            print(f"FAILED {TASK_ID} change {idx}: pattern not found in {target}", file=sys.stderr)
            print(f"Expected (first 200 chars): {repr(before[:200])}", file=sys.stderr)
            sys.exit(1)

        result = subprocess.run(
            ["sd", "-F", "-A", "-n", "1", "--", before, after, target],
            capture_output=True, text=True,
        )
        if result.returncode != 0:
            print(f"FAILED {TASK_ID} change {idx}: sd error: {result.stderr}", file=sys.stderr)
            sys.exit(result.returncode)

        new_content = target_path.read_text()
        if after and after not in new_content:
            print(f"FAILED {TASK_ID} change {idx}: replacement not found after apply", file=sys.stderr)
            sys.exit(1)

        print(f"OK {TASK_ID} change {idx}: applied to {target}")

print(f"OK {TASK_ID}: all changes applied")
